module packet_filter(  
    input [3:0] protocol,  
    input [3:0] port,  
    output reg obf_allow  
);  
    always @(*) begin  
        if (protocol == 4'b0001 && (port >= 4'b0001 && port <= 4'b0010))  
            obf_allow = 1;  
        else  
            obf_allow = 0;  
    end  
endmodule
